import type { FixTask, TaskReport } from "../core/models.js";
import type { AIModelConfig } from "../../../types.js";
import type { EventEmitter } from "../../../execution/round_executor.js";

export interface CompilationCheckResult {
  success: boolean;
  errors_text: string;
  raw_result: unknown;
}

export interface CompilationFixRuntime {
  compile(project_abs_path: string, signal?: AbortSignal): Promise<CompilationCheckResult>;
  run_fix_task(
    project_abs_path: string,
    task: FixTask,
    round_num: number,
    timeout_sec: number,
    signal?: AbortSignal,
    batch_index?: number,
    total_batches?: number,
  ): Promise<TaskReport>;
  log(message: string): void;
  report_progress?(message: string, progress?: number): void;
  emit_main_chat_round_started?(roundId: string, roundIndex?: number, order?: number): void;
  emit_main_chat_text?(roundId: string, text: string, contentType?: "text" | "thinking"): void;
  emit_main_chat_tool_event?(roundId: string, toolEvent: Record<string, unknown>): void;
  emit_main_chat_panel_marker?(roundNum: number, anchorRoundId?: string, order?: number): void;
}

/**
 * 编译修复运行时上下文（与具体调用入口解耦）
 * ToolContext / WorkflowContext 均可通过适配转换到该结构。
 */
export interface CompilationFixRuntimeContext {
  session_id: string;
  turn_id: string;
  turn_index?: number;
  workspace_path?: string;
  signal?: AbortSignal;
  model_config?: AIModelConfig;
  emit_event?: EventEmitter;
  on_log?: (message: string) => void;
  on_progress?: (message: string, progress?: number) => void;
}
